/* 混合使用 HAL + LL 的示例：
 * HAL 负责时钟配置（CubeMX 生成的正确代码）
 * LL 负责外设初始化（精简、可预测、体积可控）
 *
 * STM32F407 @ 168MHz:
 *   SYSCLK = 168MHz, AHB = 168MHz, APB1 = 42MHz, APB2 = 84MHz
 *   USART1 目标波特率 115200
 *   USART1 挂载 APB2 (84MHz)，BRR = 84MHz / 115200 = 728.26 = 0x02D8
 */

#include "stm32f4xx_hal.h"
#include "stm32f4xx_ll_usart.h"
#include "stm32f4xx_ll_gpio.h"
#include "stm32f4xx_ll_rcc.h"

/* HAL 层：时钟配置（由 CubeMX 生成，保持原样）*/
extern void SystemClock_Config(void);

/* LL 层：USART1 初始化（115200, 8N1, 无流控）*/
void Uart1_LL_Init(void) {
    /* 1. GPIO 配置：PA9 = TX, PA10 = RX */
    LL_AHB1_GRP1_EnableClock(LL_AHB1_GRP1_PERIPH_GPIOA);
    LL_GPIO_InitTypeDef gpio = {
        .Pin = LL_GPIO_PIN_9 | LL_GPIO_PIN_10,
        .Mode = LL_GPIO_MODE_AF,
        .Speed = LL_GPIO_SPEED_FREQ_VERY_HIGH,
        .OutputType = LL_GPIO_OUTPUT_PUSHPULL,
        .Pull = LL_GPIO_PULL_NO,
        .Alternate = LL_GPIO_AF_7  /* AF7 = USART1 */
    };
    LL_GPIO_Init(GPIOA, &gpio);

    /* 2. USART1 时钟使能 */
    LL_APB2_GRP1_EnableClock(LL_APB2_GRP1_PERIPH_USART1);

    /* 3. 配置 USART1：波特率 / 数据位 / 停止位 / 校验 / 收发模式 */
    LL_USART_Disable(USART1);  /* 必须先禁用才能配置 */
    LL_USART_SetDataWidth(USART1, LL_USART_DATAWIDTH_8B);
    LL_USART_SetOverSampling(USART1, LL_USART_OVERSAMPLING_16);
    LL_USART_SetPrescaler(USART1, 0);  /* 无分频 */
    LL_USART_SetBaudRate(USART1, 42000000UL, LL_USART_OVERSAMPLING_16,
                         LL_USART_PARITY_NONE, 115200);
    LL_USART_SetStopBitsLength(USART1, LL_USART_STOPBITS_1);
    LL_USART_SetTXRXDirections(USART1, LL_USART_TX_RX);
    LL_USART_EnableIT_RXNE(USART1);  /* 接收中断 */
    LL_USART_Enable(USART1);         /* 使能 USART */

    /* 4. NVIC 中断配置 */
    NVIC_SetPriority(USART1_IRQn, 5);  /* 低优先级，避免打断关键中断 */
    NVIC_EnableIRQ(USART1_IRQn);
}

/* 发送一个字节：对比 HAL vs LL 的指令开销
 * LL 路径：直接写 DR 寄存器 → 1 条 STR 指令 (~60ns)
 * HAL 路径：HAL_UART_Transmit → 锁检查 + 超时循环 + 轮询 TXE → 约 48 条指令 (~286ns)
 */
void Uart1_LL_SendByte(uint8_t byte) {
    while (!LL_USART_IsActiveFlag_TXE(USART1));  /* 等 TXE 标志 */
    LL_USART_TransmitData8(USART1, byte);         /* 直接写 DR */
}

/* 代价分析：LL 比 HAL 多了 3 行手动管理代码（禁用、配置、使能），
 * 但省下了约 16KB flash、~200ns/次调用、以及不可预测的延迟。
 * 代价是开发者需要自己理解 BRR 寄存器的计算逻辑。
 * 对于量产 100 万台的产品，16KB flash × 0.3 元/KB = 省下 4800 元/批次，
 * 200ns × 100 万次/秒 = 每天节省 20ms CPU 时间，可能不足以成为理由；
 * 但对于电池供电设备，CPU 少跑 200ns 可能意味着多活几小时 —— 这就是取舍。

#include "stm32f4xx_ll_i2c.h"
#include "stm32f4xx_ll_gpio.h"
#include "stm32f4xx_ll_rcc.h"

/* I2C1 初始化：400kHz 快速模式，SCL=PA8, SDA=PA9
 *
 * 时序计算参考 ST AN4235：
 *   APB1 = 42MHz, Freq = 400kHz, duty = 50% (FAST+)
 *   SCL = (SCLL + 1) × TPRE × (1 + SCL_HIGHTIME / SCL_LOWTIME)
 *   SDA = (SCLL + 1) × TPRE × (1 + SETUP + HOLD)
 *
 * ST 官网提供时序计算器，推荐值：0x1093217F
 * 此值使 SCL 实际频率 395kHz，满足 ±10% 容差 */
void I2C1_LL_Init(void) {
    /* 1. 使能 GPIOA 和 I2C1 时钟 */
    LL_AHB1_GRP1_EnableClock(LL_AHB1_GRP1_PERIPH_GPIOA);
    LL_APB1_GRP1_EnableClock(LL_APB1_GRP1_PERIPH_I2C1);

    /* 2. GPIO 配置：PA8 = SCL, PA9 = SDA, AF4 */
    LL_GPIO_InitTypeDef gpio = {
        .Pin = LL_GPIO_PIN_8 | LL_GPIO_PIN_9,
        .Mode = LL_GPIO_MODE_AF,
        .Speed = LL_GPIO_SPEED_FREQ_VERY_HIGH,
        .OutputType = LL_GPIO_OUTPUT_OPENDRAIN,
        .Pull = LL_GPIO_PULL_NO,
        .Alternate = LL_GPIO_AF_4  /* AF4 = I2C1 */
    };
    LL_GPIO_Init(GPIOA, &gpio);

    /* 3. I2C 禁用状态下配置参数（必须先 Disable！）*/
    LL_I2C_Disable(I2C1);

    /* 4. 设置地址模式（7位）和自身地址（如需要 Master 发地址）*/
    LL_I2C_SetOwnAddress1(I2C1, 0x00, LL_I2C_OWNADDRESS1_7BIT);

    /* 5. 设置时序 —— 最关键的一步 */
    LL_I2C_SetTiming(I2C1, 0x1093217F);
    /* 0x1093217F = SCLLow + SCLHigh + SETUP + HOLD 的综合值 */

    /* 6. 启用 I2C 和 PEC（协议错误校验，可选）*/
    LL_I2C_Enable(I2C1);

    /* 7. 等待 I2C 就绪 —— 这是常见踩坑点 */
    /* 实测：不加此等待，第一次 I2C 启动可能发失败（ISREADY 未置位）*/
    uint32_t timeout = 1000;
    while (!LL_I2C_IsActiveFlag_ISREADY(I2C1) && timeout--) {
        /* 超时 1000 次 × ~1µs = 1ms，不会阻塞太久 */
    }
    if (timeout == 0) {
        /* I2C 初始化失败，检查时钟配置或硬件连接 */
    }
}

/* 快速读取一个 I2C 设备寄存器 */
uint8_t I2C1_LL_ReadReg(uint8_t addr, uint8_t reg) {
    /* 发送器件地址 + 寄存器地址（写传输）*/
    LL_I2C_GenerateStartCondition(I2C1);
    while (!LL_I2C_IsActiveFlag_SB(I2C1));  /* 等 START 已发送 */
    LL_I2C_TransmitData8(I2C1, addr << 1);  /* 7位地址左移1位 */
    while (!LL_I2C_IsActiveFlag_ADDR(I2C1));  /* 等 ACK */
    (void)I2C1->SR1;  /* 清除 ADDR 标志 */
    (void)I2C1->SR2;

    LL_I2C_TransmitData8(I2C1, reg);  /* 发送寄存器地址 */
    while (!LL_I2C_IsActiveFlag_STOPF(I2C1));  /* 发 RESTART */

    /* 发送读传输 */
    LL_I2C_GenerateStartCondition(I2C1);
    while (!LL_I2C_IsActiveFlag_SB(I2C1));
    LL_I2C_TransmitData8(I2C1, (addr << 1) | 1);  /* 写操作 | 1 = 读 */
    while (!LL_I2C_IsActiveFlag_ADDR(I2C1));
    (void)I2C1->SR1;
    (void)I2C1->SR2;

    /* 读数据并发送 NACK 结束 */
    uint8_t data = LL_I2C_ReceiveData8(I2C1);
    LL_I2C_AcknowledgeNextData(I2C1, LL_I2C_NACK);  /* NACK */
    LL_I2C_GenerateStopCondition(I2C1);  /* 发 STOP */
    return data;
}

/* 中断优先级说明：
 * I2C 中断默认优先级 5，适合非关键路径。
 * 如果 I2C 用于关键传感器（如 IMU），建议将 I2C + 数据就绪中断提升到优先级 3，
 * 确保 IMU 数据在下次采样前被读出，避免溢出。

// ====== 陷阱1 演示：DMA 状态不一致 ======
// HAL 管理的 DMA 状态
extern DMA_HandleTypeDef hdma_usart1_rx;

/* 错误：LL 读 DMA_SxNDTR 和 HAL 读 hdma 的 RemainigBytes 不一致 */
void Bad_DMA_Check(void) {
    // HAL 说还有 10 字节
    uint16_t remaining_hal = hdma_usart1_rx.Instance->NDTR;

    // LL 代码可能读到的值不同（取决于 NDTR 是否被 DMA 硬件更新了）
    uint16_t remaining_ll = LL_DMA_IsDMA_Ready(DMA1, LL_DMA_STREAM_5);

    // 两者可能不同步！
}

// ====== 陷阱2 演示：中断标志清除 ======
// HAL UART 接收中断回调中混用 LL 清除
void USART1_IRQHandler(void) {
    // HAL 内部已经做了这个检查
    if (__HAL_UART_GET_FLAG(&huart1, UART_FLAG_RXNE)) {
        // HAL 在 HAL_UART_IRQHandler 里自动清除了标志
        // 但如果这里又调 LL 清除，可能清除过头
        LL_USART_ClearFlag_RXNE(USART1);  // 危险！

        // HAL 回调
        HAL_UART_IRQHandler(&huart1);
    }
}

// ====== 陷阱3 演示：Flash 溢出检测 ======
// 在链接脚本 (.ld) 中添加内存段检查
// MEMORY {
//   FLASH (rx) : ORIGIN = 0x08000000, LENGTH = 64K
// }
// .text : { *(.text*) } > FLASH
// 编译后如果 .text 超过 64K，链接器会报错但不会阻止构建
// 建议在 Makefile 中加检查：
// size build/firmware.elf | grep .text
// 如果 .text > 55000，发出警告（64KB - 5.5KB 安全余量）

// ====== 陷阱4 演示：时钟超频检测 ======
void Clock_Verify(void) {
    // 确保 APB1 分频器不超过 42MHz
    RCC_ClkInitTypeDef clk;
    HAL_RCC_GetClockConfig(&clk, RCC_SYSCLK_DIV_POSITION);

    // APB1 prescaler: RCC_CFGR |= (presc << 10)
    // 如果 presc = 0 (÷1)，APB1 = HCLK = 168MHz → 超频！
    // F4 的 APB1 最大时钟 = 42MHz（即 ÷4 或更大）

    uint32_t apb1_freq = SystemCoreClock / (1UL << (clk.APB1CLKDivider >> 10));
    if (apb1_freq > 42000000UL) {
        // APB1 超频了！外设可能异常工作
        // TIM3 频率翻倍、UART 波特率错误、I2C 时序超差
    }
}

/* ========== 改进前：HAL 回调地狱（坏味道）========== */
// 4层回调嵌套，缓冲区管理分散在 3 个函数里
static uint8_t hal_spi_buf[4096];
static void (*hal_transfer_done_cb)(void) = NULL;

void HAL_SPI_TxRxCpltCallback(SPI_HandleTypeDef *hspi) {
    // 第1层回调：DMA传输完成
    // 问题：用户代码要通过全局指针传回调
    if (hal_transfer_done_cb) {
        hal_transfer_done_cb();  // 第2层回调
    }
}

void SPI_Transfer_SendAndProcess(void) {
    hal_transfer_done_cb = User_Process_SPI_Data;  // 全局指针
    HAL_SPI_TransmitReceive_DMA(&hspi1, tx_buf, rx_buf, 4096);  // 第3层
    // 问题：无法取消传输，无法超时检测
}

/* ========== 改进后：LL 状态机 ========== */

typedef enum {
    SPI_STATE_IDLE = 0,
    SPI_STATE_TX,           /* DMA TX 进行中 */
    SPI_STATE_RX,           /* DMA RX 进行中 */
    SPI_STATE_DUAL,         /* DMA 双缓冲 TX+RX */
    SPI_STATE_DONE          /* 传输完成 */
} SpiState_t;

static SpiState_t spi_state = SPI_STATE_IDLE;
static volatile uint8_t spi_transfer_timeout = 0;

/* 启动一次 SPI DMA 传输（同步，带超时）
 * 返回值：0 = 成功, -1 = 超时, -2 = 总线忙 */
int32_t SPI_LL_Transfer_Dual(uint8_t* tx, uint8_t* rx, uint32_t len) {
    /* 第1步：检查总线是否空闲 */
    if (spi_state != SPI_STATE_IDLE) {
        return -2;  /* 总线忙 */
    }

    /* 第2步：配置 DMA 双缓冲 */
    spi_state = SPI_STATE_DUAL;
    LL_DMA_SetDataLength(DMA2, LL_DMA_STREAM_3, len);  /* TX DMA */
    LL_DMA_SetMemoryAddress(DMA2, LL_DMA_STREAM_3, (uint32_t)tx);
    LL_DMA_SetDataLength(DMA2, LL_DMA_STREAM_5, len);  /* RX DMA */
    LL_DMA_SetMemoryAddress(DMA2, LL_DMA_STREAM_5, (uint32_t)rx);

    /* 第3步：配置 SPI，启动 DMA 请求 */
    LL_SPI_EnableDMAReq_TX(SPI1);
    LL_SPI_EnableDMAReq_RX(SPI1);
    LL_SPI_Enable(SPI1);

    /* 第4步：等待传输完成（轮询 + 超时）*/
    spi_transfer_timeout = 1000;  /* ~10ms 超时 @ 1MHz SPI */
    while (spi_state == SPI_STATE_DUAL && spi_transfer_timeout--) {
        if (LL_SPI_IsActiveFlag_TXE(SPI1) && 
            LL_SPI_IsActiveFlag_RXNE(SPI1) &&
            LL_DMA_IsActiveFlag_TC(DMA2, LL_DMA_STREAM_3)) {
            spi_state = SPI_STATE_DONE;
            break;
        }
    }

    /* 第5步：清理 */
    LL_SPI_DisableDMAReq_TX(SPI1);
    LL_SPI_DisableDMAReq_RX(SPI1);
    LL_SPI_Enable(SPI1);  /* 重新使能，恢复总线 */

    return (spi_state == SPI_STATE_DONE) ? 0 : -1;  /* -1 = 超时 */
}

/* 代价分析：
 * 改进前：回调驱动，无法超时，代码分散
 * 改进后：轮询等待，可超时，代码集中
 * 代价：阻塞等待 ~2ms（SPI @ 1MHz, 4096 字节），不适合高实时性场景
 * 如果非阻塞需求，可以用 LL + DMA 传输完成中断 + 状态机，
 * 但需要在 DMA 回调中更新状态并触发用户回调 */

/* ========== 改进收益 ==========
 * 代码行数：从分散在 3 个函数 ~120 行 → 集中在 1 个函数 ~45 行
 * Flash 节省：去掉 HAL 回调注册机制（~2KB），去掉全局回调指针（~16B）
 * 可维护性：从「需要画回调流程图才能理解」→「读代码就能看懂执行路径」
 * 可预测性：从「回调触发时间不确定」→「传输完成时间 ~len / SPI_baudrate」
 * 代价：从异步变成同步，失去并行性。如果 SPI 外设唯一且需要高吞吐，
 *       需要用双缓冲 + 双 DMA 通道实现真正的异步，代价是复杂度翻倍 */
